const body = $input.first().json.body;

const prompt = `You are a content moderator for MamVibe, a Bulgarian marketplace for families selling baby and children's items.
Review this listing submission and provide a moderation recommendation.

Title: ${body.title || 'N/A'}
Category: ${body.category || 'N/A'}
Listing type: ${body.listingType || 'N/A'}
Price: ${body.price ? body.price + ' BGN' : 'Free / Donation'}
Description: ${body.description || 'No description provided'}

Respond with ONLY valid JSON, no other text:
{"recommendation": "approve", "reason": "brief reason here", "flags": []}

recommendation must be exactly one of:
- "approve": clearly appropriate baby/children item with acceptable description
- "review": needs manual check (vague description, unusual item, borderline content)
- "reject": inappropriate content, spam, dangerous item, or completely unrelated

flags: array of concern tags, empty if none. Examples: ["low_quality_description", "suspicious_price", "wrong_category"]`;

const requestBody = JSON.stringify({
  model: "claude-haiku-4-5-20251001",
  max_tokens: 200,
  messages: [{ role: "user", content: prompt }]
});

return [{ json: { ...($input.first().json), requestBody } }];

const apiResponse = $input.first().json;
const webhookBody = $('Webhook: Item Pending').item.json.body;

let aiResult = {
  recommendation: "review",
  reason: "AI screening unavailable — please review manually.",
  flags: []
};

try {
  const text = apiResponse.content[0].text.trim();
  aiResult = JSON.parse(text);
} catch (e) {
  // use fallback
}

const colorMap = { approve: "#27ae60", review: "#e67e22", reject: "#e74c3c" };
const labelMap = {
  approve: "Auto-Approve Suggested",
  review: "Manual Review Needed",
  reject: "Reject Suggested"
};

return [{
  json: {
    ...webhookBody,
    aiRecommendation: aiResult.recommendation,
    aiRecommendationLabel: labelMap[aiResult.recommendation] || aiResult.recommendation,
    aiReason: aiResult.reason,
    aiFlags: (aiResult.flags || []).join(", ") || "none",
    aiBadgeColor: colorMap[aiResult.recommendation] || "#888"
  }
}];
